const ga4Property = {
  propertyId: 'GA4-123456789',
  propertyName: 'MyFitnessApp',
  streams: [
    {
      type: 'web',
      name: 'WebサイトStream',
      measurementId: 'G-ABCDEF1234',
      lastReceived: '2024-08-01',
      eventsLast30Days: 45000
    },
    {
      type: 'ios',
      name: 'iOSアプリStream',
      bundleId: 'com.example.myfitness',
      lastReceived: '2024-08-01',
      eventsLast30Days: 120000
    },
    {
      type: 'android',
      name: 'AndroidアプリStream',
      packageName: 'com.example.myfitness',
      lastReceived: '2024-07-20',
      eventsLast30Days: 0
    }
  ]
};

function checkStreamHealth(stream) {
  const isHealthy = stream.lastReceived.startsWith('2024-08') && stream.eventsLast30Days > 0;
  return {
    name: stream.name,
    type: stream.type,
    status: isHealthy ? '正常' : '要確認'
  };
}

console.log('=== データストリーム健全性チェック ===');
ga4Property.streams.forEach(stream => {
  const result = checkStreamHealth(stream);
  const icon = result.status === '正常' ? '✅' : '⚠️';
  console.log(`${icon} [${result.type.toUpperCase()}] ${result.name}: ${result.status}`);
});
